import { LoanInfo, Installments } from "./../../../Models/Loan/LoanInfo";
import { Component, OnInit } from "@angular/core";
import { SearchResult } from "../../../Models/References/SearchResult";
import { EnvService } from "src/app/core/services/env.service";
import { HttpClient } from "@angular/common/http";
import { FormBuilder, FormGroup, Validators } from "@angular/forms";
import { DatePipe, formatNumber } from "@angular/common";
import { IECollectData } from "src/app/views/Models/References/ECollectData";
import { AlertController, Platform } from "@ionic/angular";
import { Subscription } from "rxjs";
import { Router } from "@angular/router";
import { AlertService } from "src/app/core/services/alert.service";
import { ReferencesService } from "src/app/core/services/references.service";
import { Funders } from "src/app/views/Models/References/Funders";
import { MohassilAuthService } from "src/app/core/services/AuthenticationServices/mohassil-auth.service";
import { UserInfo } from "src/app/core/models/UserInfo";

interface CheckFundingReferenceInterface {
  fundingRefs: {
    funder_code: string;
    funding_amount: string;
    funding_date: string;
    funding_reference_code: string;
    funding_reference_id: string;
    funding_reference_status: string;
  }[];
  iscore_external_funding: string;
}

@Component({
  selector: "app-loan-issuance",
  templateUrl: "./loan-issuance.page.html",
  styleUrls: ["./loan-issuance.page.scss"],
})
export class LoanIssuancePage implements OnInit {
  showLoader: boolean = false;
  LoanIssuanceForm: FormGroup;
  today = new Date();
  loan_date = "";
  pipe = new DatePipe("en-US");
  backButtonListener: Subscription;

  constructor(
    private env: EnvService,
    private http: HttpClient,
    private formBuilder: FormBuilder,
    private alertController: AlertController,
    private datepipe: DatePipe,
    private platform: Platform,
    private alertService: AlertService,
    private router: Router,
    private referencesService: ReferencesService,
    private authService: MohassilAuthService
  ) {}

  isSearching: boolean = true;
  SearchResult: SearchResult;
  isLoanInfoForm: boolean = false;
  LoanInfo: LoanInfo;
  LoanInstallments: Installments[];
  EcollectData: IECollectData[];
  Funders: Funders[];
  isIscore_external_funding: boolean;
  fundingReferenceResponse: CheckFundingReferenceInterface = {
    fundingRefs: [],
    iscore_external_funding: null,
  };
  userInfo: UserInfo;

  async ngOnInit() {
    this.LoanIssuanceForm = this.formBuilder.group({
      loan_status: [""],
      ecollect_code: [null],
      loan_last_trans_date: [""],
      uuc: [""],
      funder_code: [""],
      funding_reference_id: [""],
      loan_notes: [""],
    });
    this.Funders = await this.referencesService.getAllFunders();
    this.userInfo = await this.authService.getUserInfo();
    this.registerBackButtonListener();
  }

  async formSubmit() {
    if (!this.LoanIssuanceForm.valid) return;
    if (await this.alertService.SaveAlert()) {
      this.showLoader = true;

      this.LoanIssuanceForm.patchValue({
        loan_status: 1,
        uuc: this.LoanInfo.uuc,
      });

      let ecollect_code;

      if (this.LoanIssuanceForm.value.ecollect_code != null) {
        ecollect_code =
          this.LoanIssuanceForm.controls.ecollect_code.value.toString();
      }

      this.http
        .post(this.env.API_URL + "api/Loan/LoanIssuance", {
          loan_status:
            this.LoanIssuanceForm.controls.loan_status.value.toString(),
          ecollect_code: ecollect_code,
          loan_last_trans_date:
            this.LoanIssuanceForm.controls.loan_last_trans_date.value.toString(),
          uuc: this.LoanIssuanceForm.controls.uuc.value.toString(),
          loan_key: this.SearchResult.loan_key.toString(),
          funder_code:
            this.LoanIssuanceForm.controls.funder_code.value.toString(),
          funding_reference_id:
            this.LoanIssuanceForm.controls.funding_reference_id.value === null
              ? null
              : this.LoanIssuanceForm.controls.funding_reference_id.value.toString(),
          loan_notes:
            this.LoanIssuanceForm.controls.loan_notes.value === null
              ? null
              : this.LoanIssuanceForm.controls.loan_notes.value.toString(),
        })
        .subscribe({
          next: (data) => {
            this.clearForms();
            this.showLoader = false;
            this.alertService.showAlertConfirm("تم اصدار القرض", true);
          },
          error: (err) => {
            this.alertService.showAlertError(err.error, false);
            this.showLoader = false;
          },
        });
    }
  }

  clientSelected(event: SearchResult) {
    this.SearchResult = event;
    this.showLoader = true;
    this.isSearching = false;
    this.http
      .post(this.env.API_URL + "api/Loan/GetLoanInstallments", {
        loan_key: event.loan_key.toString(),
      })
      .subscribe({
        next: (data) => {
          this.LoanInfo = data["loanDisbursementDTO"];
          this.LoanInstallments = data["installments"];

          this.getEcollectData(this.SearchResult.client_key.toString());

          let ChangedFormat = this.pipe.transform(this.today, "yyyy-MM-dd");
          this.loan_date = ChangedFormat;

          this.LoanIssuanceForm.patchValue({
            loan_last_trans_date: this.loan_date,
            funder_code: this.LoanInfo.funder_code,
            funding_reference_id: this.LoanInfo.funding_reference_id,
            loan_notes: this.LoanInfo.loan_notes,
          });
          if (
            this.LoanInfo.funder_code !== null &&
            this.LoanInfo.funder_code !== ""
          )
            this.checkFundingReference(this.LoanInfo.funder_code);

          this.isLoanInfoForm = true;
          this.showLoader = false;
        },
        error: (err) => {
          this.alertService.showAlertError(err.error, false);
          this.showLoader = false;
        },
      });
  }

  checker(input: string) {
    return this.datepipe.transform(input, "yyyy-MM-dd");
  }

  getEcollectData(client_key: string) {
    this.http
      .post<IECollectData[]>(
        this.env.API_URL + "api/StaticRef/GetEcollectDataByClientKey",
        {
          client_key: client_key,
        }
      )
      .subscribe({
        next: (data) => {
          this.EcollectData = data;
          if (this.EcollectData.length != 0) {
            this.LoanIssuanceForm.patchValue({
              ecollect_code: this.EcollectData[0].ecollect_code,
            });
          }
        },
        error: (err) => {
          this.alertService.showAlertError(err.error, false);
          this.showLoader = false;
        },
      });
  }

  clearForms() {
    this.LoanInfo = null;
    this.LoanInstallments = [];
    this.EcollectData = [];
    this.LoanIssuanceForm.reset();
    this.isSearching = true;
    this.isLoanInfoForm = false;
  }

  NumberFormatStyle(number) {
    let result = formatNumber(Number(number), "en-US", "1.2-2");
    return result;
  }

  async confirm(): Promise<void> {
    let alert = this.alertController.create({
      header: "تنبيه",
      message: "هل انت متاكد من تنفيذ هذه العمليه",
      buttons: [
        {
          text: "نعم",
          role: "OK",
          cssClass: "btn-success",
          handler: () => {
            this.formSubmit();
          },
        },
        {
          text: "لا",
          cssClass: "btn-danger",
          handler: () => {},
        },
      ],
    });
    (await alert).present();
  }

  ngOnDestroy(): void {
    this.backButtonListener.unsubscribe();
  }

  registerBackButtonListener(): void {
    this.backButtonListener = this.platform.backButton.subscribeWithPriority(
      10,
      (next) => {
        this.backButton();
      }
    );
  }

  backButton(): void {
    if (this.isLoanInfoForm == true) {
      this.isLoanInfoForm = false;
      this.isSearching = true;
    } else {
      this.router.navigate(["/home"]);
    }
  }

  funderCodeChange($event) {
    if ($event.detail.value != "") {
      this.LoanIssuanceForm.patchValue({ funding_reference_id: null });
      this.checkFundingReference($event.detail.value);
    }
  }
  checkFundingReference(funder_code: string) {
    this.showLoader = true;
    this.http
      .post(this.env.API_URL + "api/LoanApplications/GetFundingReference", {
        org_code: this.userInfo.org_code,
        funder_code: funder_code,
      })
      .subscribe({
        next: (data) => {
          console.log("data", data);
          this.fundingReferenceResponse.fundingRefs = data["fundingRefs"];
          this.fundingReferenceResponse.iscore_external_funding =
            data["iscore_external_funding"];
          if (this.fundingReferenceResponse.iscore_external_funding == "1") {
            this.isIscore_external_funding = true;
            this.LoanIssuanceForm.controls[
              "funding_reference_id"
            ].setValidators([Validators.required]);
          } else {
            this.isIscore_external_funding = false;
            this.LoanIssuanceForm.controls[
              "funding_reference_id"
            ].clearValidators();
          }
          this.LoanIssuanceForm.controls[
            "funding_reference_id"
          ].updateValueAndValidity();
          this.showLoader = false;
        },
        error: (err) => {
          console.log(err);
          this.showLoader = false;
        },
      });
  }
  get GetLoanIssuanceForm() {
    return this.LoanIssuanceForm.controls;
  }
}
